-- تصحيح نص المؤشر 2-1-1-2 (تدعم المناهج لتحقيق نواتج التعلم وفق الخطة الدراسية)
UPDATE indicators SET text = 'تدعم المدرسة تنفيذ المناهج لتحقيق نواتج التعلم المستهدفة وفق الخطة الدراسية.' WHERE code = '2-1-1-2';

-- تصحيح نص المؤشر 2-1-1-5 (تنمو وتستقصي)
UPDATE indicators SET text = 'توفِّر المدرسة أنشطة تعلم تطبيقية واستقصائية تعزز النمو وترتبط بحياة الأطفال.' WHERE code = '2-1-1-5';

-- تصحيح المؤشر 2-1-1-10 ليكون المهارات الرقمية
UPDATE indicators SET text = 'تنمّي المدرسة المهارات الرقمية لدى الأطفال.', orderIndex = 10 WHERE code = '2-1-1-10';

-- إضافة المؤشر الجديد 2-1-1-11 (تعزز دافعية الأطفال)
INSERT IGNORE INTO indicators (criteriaId, code, text, orderIndex, isPrivate) VALUES
(6, '2-1-1-11', 'تعزِّز المدرسة دافعية الأطفال للتعلم، والاستمتاع به.', 11, 0);

-- تصحيح مؤشرات تقويم التعلم (المجال الثاني)
UPDATE indicators SET text = 'تحقِّق المدرسة أساليب تقويم متنوعة وفاعلة؛ لتقويم أداء الأطفال وتطورهم النمائي.' WHERE code = '2-2-1-1';
UPDATE indicators SET text = 'تحلِّل المدرسة نتائج التقويم، وتوظِّفها في دعم التعلم وتحسين نواتج التعلم بانتظام.' WHERE code = '2-2-1-2';
UPDATE indicators SET text = 'تقدِّم المدرسة التغذية الراجعة للأطفال بانتظام.' WHERE code = '2-2-1-3';

